package hydra.java.testing

import hydra.packaging.*

import hydra.testing.*

import hydra.util.*

def buildJavaTestModule(testModule: hydra.packaging.Module)(testGroup: hydra.testing.TestGroup)(testBody: scala.Predef.String): scala.Predef.String =
  {
  lazy val `ns_`: hydra.packaging.Namespace = (testModule.namespace)
  lazy val parts: Seq[scala.Predef.String] = hydra.lib.strings.splitOn(".")(`ns_`)
  lazy val packageName: scala.Predef.String = hydra.lib.strings.intercalate(".")(hydra.lib.lists.init[scala.Predef.String](parts))
  lazy val `className_`: scala.Predef.String = hydra.lib.strings.cat2(hydra.formatting.capitalize(hydra.lib.lists.last[scala.Predef.String](parts)))("Test")
  lazy val `groupName_`: scala.Predef.String = (testGroup.name)
  lazy val standardImports: Seq[scala.Predef.String] = Seq("import org.junit.jupiter.api.Test;",
     "import static org.junit.jupiter.api.Assertions.*;", "import java.util.*;", "import hydra.util.*;")
  lazy val header: scala.Predef.String = hydra.lib.strings.cat(Seq(hydra.lib.strings.cat2("// ")(hydra.constants.warningAutoGeneratedFile),
     "\n", hydra.lib.strings.cat2("// ")(`groupName_`), "\n\n", hydra.lib.strings.cat(Seq("package ",
     packageName, ";\n\n")), hydra.lib.strings.intercalate("\n")(standardImports),
     "\n\n", hydra.lib.strings.cat(Seq("public class ", `className_`, " {\n\n"))))
  hydra.lib.strings.cat(Seq(header, testBody, "\n}\n"))
}

lazy val findJavaImports: Seq[scala.Predef.String] = Seq("import org.junit.jupiter.api.Test;",
   "import static org.junit.jupiter.api.Assertions.*;", "import java.util.*;")

def formatJavaTestName(name: scala.Predef.String): scala.Predef.String =
  {
  lazy val replaced: scala.Predef.String = hydra.lib.strings.intercalate(" Neg")(hydra.lib.strings.splitOn("-")(hydra.lib.strings.intercalate("Dot")(hydra.lib.strings.splitOn(".")(hydra.lib.strings.intercalate(" Plus")(hydra.lib.strings.splitOn("+")(hydra.lib.strings.intercalate(" Div")(hydra.lib.strings.splitOn("/")(hydra.lib.strings.intercalate(" Mul")(hydra.lib.strings.splitOn("*")(hydra.lib.strings.intercalate(" Num")(hydra.lib.strings.splitOn("#")(name))))))))))))
  lazy val sanitized: scala.Predef.String = hydra.formatting.nonAlnumToUnderscores(replaced)
  lazy val `pascal_`: scala.Predef.String = hydra.formatting.convertCase(hydra.util.CaseConvention.lowerSnake)(hydra.util.CaseConvention.pascal)(sanitized)
  hydra.lib.strings.cat2("test")(`pascal_`)
}

def generateJavaTestCase[T0](groupPath: Seq[scala.Predef.String])(tcm: hydra.testing.TestCaseWithMetadata): Either[T0,
   Seq[scala.Predef.String]] =
  {
  lazy val `name_`: scala.Predef.String = (tcm.name)
  lazy val tcase: hydra.testing.TestCase = (tcm.`case`)
  tcase match
    case hydra.testing.TestCase.universal(v_TestCase_universal_ucase) => {
      lazy val `actual_`: scala.Predef.String = (v_TestCase_universal_ucase.actual)
      lazy val `expected_`: scala.Predef.String = (v_TestCase_universal_ucase.expected)
      lazy val fullName: scala.Predef.String = hydra.lib.logic.ifElse[scala.Predef.String](hydra.lib.lists.`null`[scala.Predef.String](groupPath))(`name_`)(hydra.lib.strings.intercalate("_")(hydra.lib.lists.concat2[scala.Predef.String](groupPath)(Seq(`name_`))))
      lazy val formattedName: scala.Predef.String = hydra.java.testing.formatJavaTestName(fullName)
      Right(Seq("    @Test", hydra.lib.strings.cat(Seq("    public void ", formattedName,
         "() {")), "        assertEquals(", hydra.lib.strings.cat(Seq("            ",
         `expected_`, ",")), hydra.lib.strings.cat(Seq("            ", `actual_`,
         ");")), "    }"))
    }
}

def generateJavaTestFile[T0, T1](testModule: hydra.packaging.Module)(testGroup: hydra.testing.TestGroup)(_g: T0): Either[T1,
   Tuple2[scala.Predef.String, scala.Predef.String]] = hydra.java.testing.generateTestFileWithJavaCodec(testModule)(testGroup)

def generateJavaTestGroupHierarchy[T0](groupPath: Seq[scala.Predef.String])(testGroup: hydra.testing.TestGroup): Either[T0,
   scala.Predef.String] =
  {
  lazy val `cases_`: Seq[hydra.testing.TestCaseWithMetadata] = (testGroup.cases)
  lazy val subgroups: Seq[hydra.testing.TestGroup] = (testGroup.subgroups)
  hydra.lib.eithers.bind[T0, scala.Predef.String, scala.Predef.String](hydra.lib.eithers.map[Seq[Seq[scala.Predef.String]],
     scala.Predef.String, T0]((`lines_`: Seq[Seq[scala.Predef.String]]) =>
    hydra.lib.strings.intercalate("\n\n")(hydra.lib.lists.concat[scala.Predef.String](`lines_`)))(hydra.lib.eithers.mapList[hydra.testing.TestCaseWithMetadata,
       Seq[scala.Predef.String], T0]((tc: hydra.testing.TestCaseWithMetadata) => hydra.java.testing.generateJavaTestCase(groupPath)(tc))(`cases_`)))((testCasesStr: scala.Predef.String) =>
    hydra.lib.eithers.map[scala.Predef.String, scala.Predef.String, T0]((subgroupsStr: scala.Predef.String) =>
    hydra.lib.strings.cat(Seq(testCasesStr, hydra.lib.logic.ifElse[scala.Predef.String](hydra.lib.logic.or(hydra.lib.equality.equal[scala.Predef.String](testCasesStr)(""))(hydra.lib.equality.equal[scala.Predef.String](subgroupsStr)("")))("")("\n\n"),
       subgroupsStr)))(hydra.lib.eithers.map[Seq[scala.Predef.String], scala.Predef.String,
       T0]((blocks: Seq[scala.Predef.String]) => hydra.lib.strings.intercalate("\n\n")(blocks))(hydra.lib.eithers.mapList[hydra.testing.TestGroup,
       scala.Predef.String, T0]((subgroup: hydra.testing.TestGroup) =>
    {
    lazy val groupName: scala.Predef.String = (subgroup.name)
    lazy val header: scala.Predef.String = hydra.lib.strings.cat2("    // ")(groupName)
    hydra.lib.eithers.map[scala.Predef.String, scala.Predef.String, T0]((content: scala.Predef.String) => hydra.lib.strings.cat(Seq(header,
       "\n\n", content)))(hydra.java.testing.generateJavaTestGroupHierarchy(hydra.lib.lists.concat2[scala.Predef.String](groupPath)(Seq(groupName)))(subgroup))
  })(subgroups))))
}

def generateTestFileWithJavaCodec[T0](testModule: hydra.packaging.Module)(testGroup: hydra.testing.TestGroup): Either[T0,
   Tuple2[scala.Predef.String, scala.Predef.String]] =
  hydra.lib.eithers.map[scala.Predef.String, Tuple2[scala.Predef.String, scala.Predef.String],
     T0]((testBody: scala.Predef.String) =>
  {
  lazy val testModuleContent: scala.Predef.String = hydra.java.testing.buildJavaTestModule(testModule)(testGroup)(testBody)
  lazy val `ns_`: hydra.packaging.Namespace = (testModule.namespace)
  lazy val parts: Seq[scala.Predef.String] = hydra.lib.strings.splitOn(".")(`ns_`)
  lazy val dirParts: Seq[scala.Predef.String] = hydra.lib.lists.drop[scala.Predef.String](1)(hydra.lib.lists.init[scala.Predef.String](parts))
  lazy val `className_`: scala.Predef.String = hydra.lib.strings.cat2(hydra.formatting.capitalize(hydra.lib.lists.last[scala.Predef.String](parts)))("Test")
  lazy val fileName: scala.Predef.String = hydra.lib.strings.cat2(`className_`)(".java")
  lazy val filePath: scala.Predef.String = hydra.lib.strings.cat(Seq(hydra.lib.strings.intercalate("/")(dirParts),
     "/", fileName))
  Tuple2(filePath, testModuleContent)
})(hydra.java.testing.generateJavaTestGroupHierarchy(Seq())(testGroup))

def namespaceToJavaClassName(`ns_`: hydra.packaging.Namespace): scala.Predef.String =
  hydra.lib.strings.intercalate(".")(hydra.lib.lists.map[scala.Predef.String, scala.Predef.String](hydra.formatting.capitalize)(hydra.lib.strings.splitOn(".")(`ns_`)))
